// ==================== Timestamp Token ====================

class TimestampToken {
    private final Instant created;
    private final Instant expires;
    private final String nonce;
    private final String digest;

    public TimestampToken(Instant created, Instant expires, String nonce) {
        this.created = created;
        this.expires = expires;
        this.nonce = nonce;
        this.digest = computeDigest();
    }

    private String computeDigest() {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-256");
            String data = created.toString() + "|" + expires.toString() + "|" + nonce;
            byte[] hash = md.digest(data.getBytes(StandardCharsets.UTF_8));
            return Base64.getEncoder().encodeToString(hash);
        } catch (NoSuchAlgorithmException e) {
            throw new SecurityException("SHA-256 not available", e);
        }
    }

    public Instant getCreated() { return created; }
    public Instant getExpires() { return expires; }
    public String getNonce() { return nonce; }
    public String getDigest() { return digest; }

    public boolean verifyDigest(String providedDigest) {
        return MessageDigest.isEqual(
            digest.getBytes(StandardCharsets.UTF_8),
            providedDigest.getBytes(StandardCharsets.UTF_8)
        );
    }
}

// ==================== Replay Attack Cache ====================

class ReplayProtectionCache {
    private static final Logger LOGGER = Logger.getLogger(ReplayProtectionCache.class.getName());

    private final ConcurrentHashMap<String, Instant> nonceCache = new ConcurrentHashMap<>();
    private final Duration cacheRetentionPeriod;

    public ReplayProtectionCache(Duration cacheRetentionPeriod) {
        this.cacheRetentionPeriod = cacheRetentionPeriod;
        startCleanupThread();
    }

    public boolean isReplay(String nonce, String digest) {
        String cacheKey = nonce + ":" + digest;
        Instant existing = nonceCache.putIfAbsent(cacheKey, Instant.now());
        if (existing != null) {
            LOGGER.warning("Replay attack detected for nonce: " + nonce);
            return true;
        }
        return false;
    }

    private void startCleanupThread() {
        Thread cleanupThread = new Thread(() -> {
            while (!Thread.currentThread().isInterrupted()) {
                try {
                    Thread.sleep(60000); // Clean up every minute
                    Instant cutoff = Instant.now().minus(cacheRetentionPeriod);
                    nonceCache.entrySet().removeIf(entry -> entry.getValue().isBefore(cutoff));
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    break;
                }
            }
        });
        cleanupThread.setDaemon(true);
        cleanupThread.setName("ReplayCache-Cleanup");
        cleanupThread.start();
    }
}

// ==================== WS-Security Timestamp Handler ====================

class WsSecurityTimestampHandler implements SOAPHandler<SOAPMessageContext> {

    private static final Logger LOGGER = Logger.getLogger(WsSecurityTimestampHandler.class.getName());

    private static final String WSS_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";

    // Maximum allowed clock skew between client and server
    private static final Duration MAX_CLOCK_SKEW = Duration.ofSeconds(60);

    // Maximum allowed message age
    private static final Duration MAX_MESSAGE_AGE = Duration.ofMinutes(5);

    // Maximum allowed timestamp validity window
    private static final Duration MAX_TIMESTAMP_VALIDITY = Duration.ofMinutes(5);

    private static final ReplayProtectionCache replayCache =
            new ReplayProtectionCache(Duration.ofMinutes(10));

    private static final SecureRandom secureRandom = new SecureRandom();

    @Override
    public Set<QName> getHeaders() {
        Set<QName> headers = new HashSet<>();
        headers.add(new QName(WSS_NS, "Security"));
        return headers;
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

        if (Boolean.TRUE.equals(outbound)) {
            return addTimestampToOutbound(context);
        } else {
            return validateInboundTimestamp(context);
        }
    }

    private boolean addTimestampToOutbound(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();

            if (header == null) {
                header = envelope.addHeader();
            }

            // Create WS-Security header
            SOAPHeaderElement securityHeader = header.addHeaderElement(
                    new QName(WSS_NS, "Security", "wsse"));
            securityHeader.setMustUnderstand(true);

            // Create Timestamp element
            SOAPElement timestamp = securityHeader.addChildElement("Timestamp", "wsu", WSU_NS);

            Instant now = Instant.now();
            Instant expires = now.plus(MAX_TIMESTAMP_VALIDITY);

            SOAPElement created = timestamp.addChildElement("Created", "wsu", WSU_NS);
            created.addTextNode(now.toString());

            SOAPElement expiresElem = timestamp.addChildElement("Expires", "wsu", WSU_NS);
            expiresElem.addTextNode(expires.toString());

            // Add nonce for replay protection
            String nonce = generateSecureNonce();
            SOAPElement nonceElem = timestamp.addChildElement("Nonce", "wsu", WSU_NS);
            nonceElem.addTextNode(nonce);

            // Add digest for integrity verification
            TimestampToken token = new TimestampToken(now, expires, nonce);
            SOAPElement digestElem = timestamp.addChildElement("Digest", "wsu", WSU_NS);
            digestElem.addTextNode(token.getDigest());

            message.saveChanges();
            LOGGER.info("Added WS-Security timestamp to outbound message");
            return true;

        } catch (SOAPException e) {
            LOGGER.log(Level.SEVERE, "Failed to add timestamp to outbound message", e);
            throw new WebServiceException("Failed to add security timestamp", e);
        }
    }

    private boolean validateInboundTimestamp(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();

            if (header == null) {
                LOGGER.severe("Missing SOAP header - security violation");
                generateSOAPFault(message, "Missing WS-Security header");
                return false;
            }

            TimestampToken token = extractTimestampToken(header);

            if (token == null) {
                LOGGER.severe("Missing WS-Security Timestamp - security violation");
                generateSOAPFault(message, "Missing WS-Security Timestamp");
                return false;
            }

            // Validate timestamp values
            if (!validateTimestampValues(token)) {
                LOGGER.severe("Invalid timestamp values - security violation");
                generateSOAPFault(message, "Invalid WS-Security Timestamp");
                return false;
            }

            // Verify digest integrity
            TimestampToken recomputedToken = new TimestampToken(
                    token.getCreated(), token.getExpires(), token.getNonce());
            if (!recomputedToken.verifyDigest(token.getDigest())) {
                LOGGER.severe("Timestamp digest verification failed - possible tampering");
                generateSOAPFault(message, "Timestamp integrity check failed");
                return false;
            }

            // Check for replay attacks
            if (replayCache.isReplay(token.getNonce(), token.getDigest())) {
                LOGGER.severe("Replay attack detected");
                generateSOAPFault(message, "Replay attack detected");
                return false;
            }

            LOGGER.info("WS-Security timestamp validated successfully");
            return true;

        } catch (SOAPException e) {
            LOGGER.log(Level.SEVERE, "Error validating inbound timestamp", e);
            throw new WebServiceException("Security validation failed", e);
        }
    }

    private TimestampToken extractTimestampToken(SOAPHeader header) throws SOAPException {
        Iterator<?> securityHeaders = header.getChildElements(new QName(WSS_NS, "Security"));

        if (!securityHeaders.hasNext()) {
            return null;
        }

        SOAPElement securityElement = (SOAPElement) securityHeaders.next();
        Iterator<?> timestamps = securityElement.getChildElements(new QName(WSU_NS, "Timestamp"));

        if (!timestamps.hasNext()) {
            return null;
        }

        SOAPElement timestampElement = (SOAPElement) timestamps.next();

        String createdStr = getChildElementValue(timestampElement, WSU_NS, "Created");
        String expiresStr = getChildElementValue(timestampElement, WSU_NS, "Expires");
        String nonce = getChildElementValue(timestampElement, WSU_NS, "Nonce");
        String digest = getChildElementValue(timestampElement, WSU_NS, "Digest");

        if (createdStr == null || expiresStr == null || nonce == null || digest == null) {
            LOGGER.severe("Incomplete timestamp token");
            return null;
        }

        try {
            Instant created = Instant.parse(createdStr);
            Instant expires = Instant.parse(expiresStr);
            TimestampToken token = new TimestampToken(created, expires, nonce);
            // We need to return a token that carries the provided digest for verification
            return new TimestampToken(created, expires, nonce) {
                @Override
                public String getDigest() {
                    return digest;
                }
            };
        } catch (DateTimeParseException e) {
            LOGGER.severe("Failed to parse timestamp values: " + e.getMessage());
            return null;
        }
    }

    private String getChildElementValue(SOAPElement parent, String namespace, String localName) {
        Iterator<?> children = parent.getChildElements(new QName(namespace, localName));
        if (children.hasNext()) {
            SOAPElement child = (SOAPElement) children.next();
            return child.getTextContent();
        }
        return null;
    }

    private boolean validateTimestampValues(TimestampToken token) {
        Instant now = Instant.now();
        Instant created = token.getCreated();
        Instant expires = token.getExpires();

        // 1. Expires must be after Created
        if (!expires.isAfter(created)) {
            LOGGER.severe("Timestamp expires before or at creation time");
            return false;
        }

        // 2. Check that the validity window is not unreasonably large
        Duration validity = Duration.between(created, expires);
        if (validity.compareTo(MAX_TIMESTAMP_VALIDITY.plus(MAX_CLOCK_SKEW)) > 0) {
            LOGGER.severe("Timestamp validity window too large: " + validity);
            return false;
        }

        // 3. Created time must not be too far in the future (clock skew tolerance)
        Instant maxFutureCreated = now.plus(MAX_CLOCK_SKEW);
        if (created.isAfter(maxFutureCreated)) {
            LOGGER.severe("Timestamp created time is too far in the future");
            return false;
        }

        // 4. Created time must not be too old
        Instant oldestAllowedCreated = now.minus(MAX_MESSAGE_AGE).minus(MAX_CLOCK_SKEW);
        if (created.isBefore(oldestAllowedCreated)) {
            LOGGER.severe("Timestamp created time is too old");
            return false;
        }

        // 5. Message must not be expired (with clock skew tolerance)
        Instant adjustedExpires = expires.plus(MAX_CLOCK_SKEW);
        if (now.isAfter(adjustedExpires)) {
            LOGGER.severe("Timestamp has expired");
            return false;
        }

        // 6. Validate nonce is not empty and has minimum length
        if (token.getNonce() == null || token.getNonce().length() < 16) {
            LOGGER.severe("Invalid or too short nonce");
            return false;
        }

        return true;
    }

    private String generateSecureNonce() {
        byte[] nonceBytes = new byte[32];
        secureRandom.nextBytes(nonceBytes);
        return Base64.getEncoder().encodeToString(nonceBytes);
    }

    private void generateSOAPFault(SOAPMessage message, String reason) {
        try {
            SOAPBody body = message.getSOAPPart().getEnvelope().getBody();
            body.removeContents();
            SOAPFault fault = body.addFault();
            fault.setFaultCode("wsse:InvalidSecurity");
            fault.setFaultString(reason);
            message.saveChanges();
        } catch (SOAPException e) {
            LOGGER.log(Level.SEVERE, "Failed to generate SOAP fault", e);
        }
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        LOGGER.warning("SOAP fault occurred in security handler");
        return true;
    }

    @Override
    public void close(MessageContext context) {
        // Cleanup if needed
    }
}

