class SecurityHandlerResolver implements HandlerResolver {
    @Override
    public List<Handler> getHandlerChain(PortInfo portInfo) {
        List<Handler> handlerChain = new ArrayList<>();
        handlerChain.add(new WsSecurityTimestampHandler());
        return handlerChain;
    }
}

// ==================== Payment Service Implementation ====================

@WebService(
        endpointInterface = "com.paymentgateway.PaymentService",
        serviceName = "PaymentGatewayService",
        portName = "PaymentServicePort",
        targetNamespace = "http://paymentgateway.com/ws"
)
@HandlerChain(file = "handler-chain.xml")
class PaymentServiceImpl implements PaymentService {

    private static final Logger LOGGER = Logger.getLogger(PaymentServiceImpl.class.getName());

    // In-memory store for demo purposes; use a real database in production
    private static final ConcurrentHashMap<String, PaymentRecord> paymentStore = new ConcurrentHashMap<>();
    private static final SecureRandom secureRandom = new SecureRandom();

    @Override
    public PaymentResponse processPayment(PaymentRequest request) {
        LOGGER.info("Processing payment for merchant: " + request.getMerchantId()
                + ", order: " + request.getOrderId());

        PaymentResponse response = new PaymentResponse();

        try {
            // Validate request
            validatePaymentRequest(request);

            // Generate transaction ID
            String transactionId = generateTransactionId();
            response.setTransactionId(transactionId);

            // Mask card number for logging
            String maskedCard = maskCardNumber(request.getCardNumber());
            LOGGER.info("Processing card: " + maskedCard + ", amount: "
                    + request.getAmount() + " " + request.getCurrency());

            // Simulate payment processing
            boolean approved = simulatePaymentProcessing(request);

            if (approved) {
                String authCode = generateAuthorizationCode();
                response.setStatus("APPROVED");
                response.setMessage("Payment processed successfully");
                response.setAuthorizationCode(authCode);
                response.setProcessedAt(Instant.now());

                // Store payment record
                PaymentRecord record = new PaymentRecord(
                        transactionId, request.getMerchantId(), request.getAmount(),
                        request.getCurrency(), "APPROVED", Instant.now());
                paymentStore.put(transactionId, record);

                LOGGER.info("Payment approved: " + transactionId + ", auth: " + authCode);
            } else {
                response.setStatus("DECLINED");
                response.setMessage("Payment declined by issuer");
                response.setProcessedAt(Instant.now());

                PaymentRecord record = new PaymentRecord(
                        transactionId, request.getMerchantId(), request.getAmount(),
                        request.getCurrency(), "DECLINED", Instant.now());
                paymentStore.put(transactionId, record);

                LOGGER.info("Payment declined: " + transactionId);
            }

        } catch (PaymentValidationException e) {
            LOGGER.warning("Payment validation failed: " + e.getMessage());
            response.setStatus("ERROR");
            response.setMessage("Validation error: " + e.getMessage());
            response.setProcessedAt(Instant.now());
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Payment processing error", e);
            response.setStatus("ERROR");
            response.setMessage("Internal processing error");
            response.setProcessedAt(Instant.now());
        }

        return response;
    }

    @Override
    public RefundResponse refundPayment(RefundRequest request) {
        LOGGER.info("Processing refund for transaction: " + request.getTransactionId());

        RefundResponse response = new RefundResponse();

        try {
            // Validate refund request
            if (request.getTransactionId() == null || request.getTransactionId().isEmpty()) {
                throw new PaymentValidationException("Transaction ID is required");
            }
            if (request.getAmount() <= 0) {
                throw new PaymentValidationException("Refund amount must be positive");
            }

            PaymentRecord originalPayment = paymentStore.get(request.getTransactionId());
            if (originalPayment == null) {
                response.setStatus("ERROR");
                response.setMessage("Original transaction not found");
                return response;
            }

            if (!"APPROVED".equals(originalPayment.getStatus())) {
                response.setStatus("ERROR");
                response.setMessage("Can only refund approved transactions");
                return response;
            }

            if (request.getAmount() > originalPayment.getAmount()) {
                response.setStatus("ERROR");
                response.setMessage("Refund amount exceeds original transaction amount");
                return response;
            }

            String refundId = "RF-" + generateTransactionId();
            response.setRefundId(refundId);
            response.setStatus("REFUNDED");
            response.setMessage("Refund processed successfully");
            response.setRefundedAmount(request.getAmount());

            // Update original payment status
            originalPayment.setStatus("REFUNDED");

            LOGGER.info("Refund processed: " + refundId + " for amount: " + request.getAmount());

        } catch (PaymentValidationException e) {
            response.setStatus("ERROR");
            response.setMessage("Validation error: " + e.getMessage());
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Refund processing error", e);
            response.setStatus("ERROR");
            response.setMessage("Internal processing error");
        }

        return response;
    }

    @Override
    public PaymentStatusResponse getPaymentStatus(String transactionId) {
        LOGGER.info("Querying payment status for: " + transactionId);

        PaymentStatusResponse response = new PaymentStatusResponse();

        if (transactionId == null || transactionId.isEmpty()) {
            response.setStatus("ERROR");
            return response;
        }

        PaymentRecord record = paymentStore.get(transactionId);
        if (record == null) {
            response.setTransactionId(transactionId);
            response.setStatus("NOT_FOUND");
            return response;
        }

        response.setTransactionId(record.getTransactionId());
        response.setStatus(record.getStatus());
        response.setAmount(record.getAmount());
        response.setCurrency(record.getCurrency());
        response.setCreatedAt(record.getCreatedAt());

        return response;
    }

    private void validatePaymentRequest(PaymentRequest request) throws PaymentValidationException {
        if (request == null) {
            throw new PaymentValidationException("Payment request is null");
        }
        if (request.getMerchantId() == null || request.getMerchantId().isEmpty()) {
            throw new PaymentValidationException("Merchant ID is required");
        }
        if (request.getCardNumber() == null || !isValidCardNumber(request.getCardNumber())) {
            throw new PaymentValidationException("Invalid card number");
        }
        if (request.getCardHolderName() == null || request.getCardHolderName().isEmpty()) {
            throw new PaymentValidationException("Card holder name is required");
        }
        if (request.getExpiryDate() == null || !isValidExpiryDate(request.getExpiryDate())) {
            throw new PaymentValidationException("Invalid expiry date");
        }
        if (request.getCvv() == null || !request.getCvv().matches("\\d{3,4}")) {
            throw new PaymentValidationException("Invalid CVV");
        }
        if (request.getAmount() <= 0) {
            throw new PaymentValidationException("Amount must be positive");
        }
        if (request.getAmount() > 999999.99) {
            throw new PaymentValidationException("Amount exceeds maximum limit");
        }
        if (request.getCurrency() == null || !isValidCurrency(request.getCurrency())) {
            throw new PaymentValidationException("Invalid currency code");
        }
    }

    private boolean isValidCardNumber(String cardNumber) {
        String cleaned = cardNumber.replaceAll("[\\s-]", "");
        if (!cleaned.matches("\\d{13,19}")) {
            return false;
        }
        // Luhn algorithm
        int sum = 0;
        boolean alternate = false;
        for (int i = cleaned.length() - 1; i >= 0; i--) {
            int digit = Character.getNumericValue(cleaned.charAt(i));
            if (alternate) {
                digit *= 2;
                if (digit > 9) {
                    digit -= 9;
                }
            }
            sum += digit;
            alternate = !alternate;
        }
        return sum % 10 == 0;
    }

    private boolean isValidExpiryDate(String expiryDate) {
        return expiryDate.matches("(0[1-9]|1[0-2])/\\d{2}");
    }

    private boolean isValidCurrency(String currency) {
        Set<String> validCurrencies = Set.of("USD", "EUR", "GBP", "JPY", "CAD", "AUD", "CHF");
        return validCurrencies.contains(currency.toUpperCase());
    }

    private String maskCardNumber(String cardNumber) {
        if (cardNumber == null || cardNumber.length() < 4) {
            return "****";
        }
        String cleaned = cardNumber.replaceAll("[\\s-]", "");
        return "****-****-****-" + cleaned.substring(cleaned.length() - 4);
    }

    private boolean simulatePaymentProcessing(PaymentRequest request) {
        // Simulate: decline if amount > 10000 or card starts with 4000
        String cleaned = request.getCardNumber().replaceAll("[\\s-]", "");
        if (cleaned.startsWith("4000000000000002")) {
            return false; // Test decline card
        }
        return request.getAmount() <= 10000;
    }

    private String generateTransactionId() {
        byte[] bytes = new byte[16];
        secureRandom.nextBytes(bytes);
        return "TXN-" + bytesToHex(bytes).substring(0, 20).toUpperCase();
    }

    private String generateAuthorizationCode() {
        byte[] bytes = new byte[4];
        secureRandom.nextBytes(bytes);
        return bytesToHex(bytes).substring(0, 6).toUpperCase();
    }

    private static String bytesToHex(byte[] bytes) {
        StringBuilder sb = new StringBuilder();
        for (byte b : bytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }
}

// ==================== Payment Record (Internal) ====================

class PaymentRecord {
    private final String transactionId;
    private final String merchantId;
    private final double amount;
    private final String currency;
    private volatile String status;
    private final Instant createdAt;

    public PaymentRecord(String transactionId, String merchantId, double amount,
                         String currency, String status, Instant createdAt) {
        this.transactionId = transactionId;
        this.merchantId = merchantId;
        this.amount = amount;
        this.currency = currency;
        this.status = status;
        this.createdAt = createdAt;
    }

    public String getTransactionId() { return transactionId; }
    public String getMerchantId() { return merchantId; }
    public double getAmount() { return amount; }
    public String getCurrency() { return currency; }
    public String getStatus() { return status; }
    public void setStatus(String status) { this.status = status; }
    public Instant getCreatedAt() { return createdAt; }
}

// ==================== Custom Exception ====================

class PaymentValidationException extends Exception {
    public PaymentValidationException(String message) {
        super(message);
    }
}

// ==================== Main Application / Publisher ====================

public class PaymentGatewayApplication {

    private static final Logger LOGGER = Logger.getLogger(PaymentGatewayApplication.class.getName());

    public static void main(String[] args) {
        String address = "http://0.0.0.0:8443/ws/payment";

        if (args.length > 0) {
            address = args[0];
        }

        try {
            PaymentServiceImpl implementor = new PaymentServiceImpl();
            Endpoint endpoint = Endpoint.create(implementor);

            // Attach the security handler chain
            endpoint.getBinding().setHandlerChain(
                    new SecurityHandlerResolver().getHandlerChain(null));

            endpoint.publish(address);

            LOGGER.info("Payment Gateway SOAP Service started at: " + address);
            LOGGER.info("WSDL available at: " + address + "?wsdl");
            LOGGER.info("WS-Security timestamp validation is ACTIVE");
            LOGGER.info("Replay protection is ENABLED");

            // Keep the service running
            System.out.println("Payment Gateway is running. Press Ctrl+C to stop.");

            Runtime.getRuntime().addShutdownHook(new Thread(() -> {
                LOGGER.info("Shutting down Payment Gateway...");
                endpoint.stop();
                LOGGER.info("Payment Gateway stopped.");
            }));

            // Block main thread
            Thread.currentThread().join();

        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            LOGGER.info("Payment Gateway interrupted");
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Failed to start Payment Gateway", e);
            System.exit(1);
        }
    }
}